export default {
  "head": "<style>\n/* ── Theme: System-aware ── */\n:root {\n  --font: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, sans-serif;\n  --mono: 'SF Mono', 'Cascadia Code', 'JetBrains Mono', 'Fira Code', Menlo, Consolas, monospace;\n  --content-width: 52rem;\n  --sidebar-width: 14rem;\n\n  /* Light theme (default) */\n  --bg: #ffffff;\n  --bg-subtle: #f6f8fa;\n  --bg-code: #f0f2f5;\n  --text: #1f2328;\n  --text-secondary: #59636e;\n  --text-tertiary: #8b949e;\n  --border: #d1d9e0;\n  --border-subtle: #e8ecf0;\n  --link: #0969da;\n  --kw: #cf222e;\n  --ty: #8250df;\n  --fn: #0550ae;\n  --str: #0a3069;\n  --num: #0550ae;\n  --cm: #6e7781;\n  --scanner-color: #bf8700;\n  --parser-color: #0550ae;\n  --binder-color: #1a7f37;\n  --checker-color: #8250df;\n  --solver-color: #cf222e;\n  --emitter-color: #0969da;\n  --sidebar-bg: #f6f8fa;\n  --sidebar-active: #0969da;\n  --table-stripe: #f6f8fa;\n  --highlight-bg: #fff8c5;\n}\n\n@media (prefers-color-scheme: dark) {\n  :root {\n    --bg: #0d1117;\n    --bg-subtle: #161b22;\n    --bg-code: #1c2128;\n    --text: #e6edf3;\n    --text-secondary: #8b949e;\n    --text-tertiary: #6e7681;\n    --border: #30363d;\n    --border-subtle: #21262d;\n    --link: #58a6ff;\n    --kw: #ff7b72;\n    --ty: #d2a8ff;\n    --fn: #79c0ff;\n    --str: #a5d6ff;\n    --num: #79c0ff;\n    --cm: #8b949e;\n    --scanner-color: #e3b341;\n    --parser-color: #58a6ff;\n    --binder-color: #3fb950;\n    --checker-color: #d2a8ff;\n    --solver-color: #ff7b72;\n    --emitter-color: #79c0ff;\n    --sidebar-bg: #161b22;\n    --sidebar-active: #58a6ff;\n    --table-stripe: #161b22;\n    --highlight-bg: #2d1d00;\n  }\n}\n\n/* ── Reset & Base ── */\n*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }\n\nbody {\n  font-family: var(--font);\n  font-size: 16px;\n  line-height: 1.8;\n  color: var(--text);\n  background: var(--bg);\n  -webkit-font-smoothing: antialiased;\n}\n\n/* ── Layout ── */\n.page {\n  display: flex;\n  min-height: 100vh;\n}\n\n.sidebar {\n  position: fixed;\n  top: 0;\n  left: 0;\n  width: var(--sidebar-width);\n  height: 100vh;\n  overflow-y: auto;\n  padding: 1.5rem 0;\n  background: var(--sidebar-bg);\n  border-right: 1px solid var(--border-subtle);\n  font-size: 0.8rem;\n  z-index: 10;\n}\n\n.sidebar-title {\n  font-weight: 700;\n  font-size: 0.9rem;\n  padding: 0 1rem 1rem;\n  color: var(--text);\n  border-bottom: 1px solid var(--border-subtle);\n  margin-bottom: 0.75rem;\n}\n\n.sidebar a {\n  display: block;\n  padding: 0.25rem 1rem;\n  color: var(--text-secondary);\n  text-decoration: none;\n  line-height: 1.6;\n  border-left: 2px solid transparent;\n}\n\n.sidebar a:hover {\n  color: var(--text);\n}\n\n.sidebar a.active {\n  color: var(--sidebar-active);\n  border-left-color: var(--sidebar-active);\n  font-weight: 600;\n}\n\n.sidebar .sub {\n  padding-left: 1.75rem;\n  font-size: 0.75rem;\n}\n\n.content {\n  margin-left: var(--sidebar-width);\n  max-width: var(--content-width);\n  padding: 2rem 2.5rem 6rem;\n}\n\n/* ── Mobile sidebar ── */\n.menu-toggle {\n  display: none;\n  position: fixed;\n  top: 0.75rem;\n  left: 0.75rem;\n  z-index: 20;\n  background: var(--bg-subtle);\n  border: 1px solid var(--border);\n  border-radius: 6px;\n  padding: 0.4rem 0.6rem;\n  cursor: pointer;\n  color: var(--text);\n  font-size: 1.2rem;\n  line-height: 1;\n}\n\n@media (max-width: 860px) {\n  .sidebar { transform: translateX(-100%); transition: transform 0.2s; }\n  .sidebar.open { transform: translateX(0); box-shadow: 4px 0 20px rgba(0,0,0,0.2); }\n  .content { margin-left: 0; padding: 3rem 1.5rem 6rem; }\n  .menu-toggle { display: block; }\n}\n\n/* ── Typography ── */\nh1 {\n  font-size: 2rem;\n  font-weight: 700;\n  letter-spacing: -0.02em;\n  margin-bottom: 0.25rem;\n}\n\n.page-subtitle {\n  font-size: 1.1rem;\n  color: var(--text-secondary);\n  margin-bottom: 0.5rem;\n}\n\n.page-description {\n  color: var(--text-secondary);\n  font-size: 0.95rem;\n  margin-bottom: 2.5rem;\n  max-width: 50rem;\n  padding-bottom: 2rem;\n  border-bottom: 1px solid var(--border-subtle);\n}\n\nh2 {\n  font-size: 1.5rem;\n  font-weight: 700;\n  margin: 3rem 0 1rem;\n  padding-top: 1rem;\n  letter-spacing: -0.01em;\n}\n\nh3 {\n  font-size: 1.15rem;\n  font-weight: 600;\n  margin: 2rem 0 0.75rem;\n  color: var(--text);\n}\n\nh4 {\n  font-size: 1rem;\n  font-weight: 600;\n  margin: 1.5rem 0 0.5rem;\n}\n\np {\n  margin-bottom: 1rem;\n  max-width: 65ch;\n  color: var(--text);\n}\n\na { color: var(--link); text-decoration: none; }\na:hover { text-decoration: underline; }\n\n/* ── Code ── */\ncode {\n  font-family: var(--mono);\n  font-size: 0.88em;\n  background: var(--bg-code);\n  padding: 0.15em 0.4em;\n  border-radius: 4px;\n}\n\npre {\n  background: var(--bg-code);\n  border: 1px solid var(--border-subtle);\n  border-radius: 8px;\n  padding: 1.25rem 1.5rem;\n  overflow-x: auto;\n  font-family: var(--mono);\n  font-size: 0.85rem;\n  line-height: 1.7;\n  margin: 1.25rem 0;\n}\n\npre code {\n  background: none;\n  padding: 0;\n  font-size: inherit;\n}\n\n.kw { color: var(--kw); }\n.ty { color: var(--ty); }\n.fn { color: var(--fn); }\n.str { color: var(--str); }\n.num { color: var(--num); }\n.cm { color: var(--cm); font-style: italic; }\n\n/* ── Tables ── */\ntable {\n  width: 100%;\n  border-collapse: collapse;\n  margin: 1.25rem 0;\n  font-size: 0.9rem;\n}\n\nth {\n  text-align: left;\n  padding: 0.6rem 1rem;\n  border-bottom: 2px solid var(--border);\n  font-weight: 600;\n  font-size: 0.8rem;\n  text-transform: uppercase;\n  letter-spacing: 0.04em;\n  color: var(--text-secondary);\n}\n\ntd {\n  padding: 0.6rem 1rem;\n  border-bottom: 1px solid var(--border-subtle);\n  vertical-align: top;\n}\n\ntr:nth-child(even) { background: var(--table-stripe); }\n\n/* ── SVG Diagrams ── */\n.diagram {\n  margin: 1.5rem 0;\n  overflow-x: auto;\n  text-align: center;\n}\n\n.diagram svg {\n  max-width: 100%;\n  height: auto;\n}\n\n/* ── Trace step styling ── */\n.trace-step {\n  border-left: 3px solid var(--border);\n  padding-left: 1.5rem;\n  margin: 1.5rem 0;\n}\n\n.trace-step.scanner { border-left-color: var(--scanner-color); }\n.trace-step.parser { border-left-color: var(--parser-color); }\n.trace-step.binder { border-left-color: var(--binder-color); }\n.trace-step.checker { border-left-color: var(--checker-color); }\n.trace-step.solver { border-left-color: var(--solver-color); }\n.trace-step.diagnostic { border-left-color: var(--emitter-color); }\n\n.step-label {\n  font-weight: 700;\n  font-size: 0.75rem;\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n  margin-bottom: 0.5rem;\n}\n\n.step-label.scanner { color: var(--scanner-color); }\n.step-label.parser { color: var(--parser-color); }\n.step-label.binder { color: var(--binder-color); }\n.step-label.checker { color: var(--checker-color); }\n.step-label.solver { color: var(--solver-color); }\n.step-label.diagnostic { color: var(--emitter-color); }\n\n/* ── Callout / aside ── */\n.callout {\n  background: var(--bg-subtle);\n  border: 1px solid var(--border-subtle);\n  border-left: 3px solid var(--link);\n  border-radius: 6px;\n  padding: 1rem 1.25rem;\n  margin: 1.25rem 0;\n  font-size: 0.9rem;\n}\n\n.callout p { margin-bottom: 0.5rem; }\n.callout p:last-child { margin-bottom: 0; }\n\n.callout-title {\n  font-weight: 700;\n  font-size: 0.8rem;\n  text-transform: uppercase;\n  letter-spacing: 0.05em;\n  color: var(--link);\n  margin-bottom: 0.4rem;\n}\n\n/* ── Token table (inline) ── */\n.token-table {\n  font-family: var(--mono);\n  font-size: 0.85rem;\n}\n\n.token-table td:first-child {\n  white-space: nowrap;\n  font-weight: 600;\n}\n\n/* ── Node layout diagram ── */\n.node-layout {\n  display: grid;\n  grid-template-columns: repeat(4, 1fr);\n  gap: 0;\n  margin: 1rem 0;\n  border: 1px solid var(--border);\n  border-radius: 6px;\n  overflow: hidden;\n  font-family: var(--mono);\n  font-size: 0.8rem;\n  text-align: center;\n  max-width: 32rem;\n}\n\n.node-layout .cell {\n  padding: 0.6rem 0.4rem;\n  border-right: 1px solid var(--border-subtle);\n  background: var(--bg-subtle);\n}\n\n.node-layout .cell:last-child { border-right: none; }\n\n.node-layout .cell-label {\n  display: block;\n  font-weight: 700;\n  font-size: 0.75rem;\n  margin-bottom: 0.2rem;\n}\n\n.node-layout .cell-size {\n  display: block;\n  font-size: 0.7rem;\n  color: var(--text-tertiary);\n}\n\n/* ── Separator ── */\nhr {\n  border: none;\n  border-top: 1px solid var(--border-subtle);\n  margin: 3rem 0;\n}\n\n/* ── Footer ── */\nfooter {\n  margin-top: 4rem;\n  padding-top: 2rem;\n  border-top: 1px solid var(--border-subtle);\n  color: var(--text-secondary);\n  font-size: 0.85rem;\n}\n\n/* ── Lists ── */\nul, ol {\n  margin: 0.75rem 0 1rem 1.5rem;\n}\n\nli {\n  margin-bottom: 0.35rem;\n}\n\n/* ── Inline label ── */\n.label {\n  display: inline-block;\n  font-family: var(--mono);\n  font-size: 0.75rem;\n  font-weight: 600;\n  padding: 0.1rem 0.5rem;\n  border-radius: 4px;\n  vertical-align: middle;\n}\n\n.label.scanner { background: color-mix(in srgb, var(--scanner-color), transparent 85%); color: var(--scanner-color); }\n.label.parser { background: color-mix(in srgb, var(--parser-color), transparent 85%); color: var(--parser-color); }\n.label.binder { background: color-mix(in srgb, var(--binder-color), transparent 85%); color: var(--binder-color); }\n.label.checker { background: color-mix(in srgb, var(--checker-color), transparent 85%); color: var(--checker-color); }\n.label.solver { background: color-mix(in srgb, var(--solver-color), transparent 85%); color: var(--solver-color); }\n.label.emitter { background: color-mix(in srgb, var(--emitter-color), transparent 85%); color: var(--emitter-color); }\n</style>",
  "body": "<button class=\"menu-toggle\" onclick=\"document.querySelector('.sidebar').classList.toggle('open')\" aria-label=\"Toggle navigation\">&#9776;</button>\n\n<div class=\"page\">\n\n<!-- ── Sidebar ── -->\n<nav class=\"sidebar\" id=\"sidebar\">\n  <div class=\"sidebar-title\">How tsz Works</div>\n  <a href=\"#intro\">Introduction</a>\n  <a href=\"#pipeline\">1. The Pipeline</a>\n  <a href=\"#trace\">2. Full Trace</a>\n  <a href=\"#trace-scanner\" class=\"sub\">Scanner</a>\n  <a href=\"#trace-parser\" class=\"sub\">Parser</a>\n  <a href=\"#trace-binder\" class=\"sub\">Binder</a>\n  <a href=\"#trace-checker\" class=\"sub\">Checker</a>\n  <a href=\"#trace-solver\" class=\"sub\">Solver</a>\n  <a href=\"#trace-diagnostic\" class=\"sub\">Diagnostic</a>\n  <a href=\"#memory\">3. Memory Architecture</a>\n  <a href=\"#types\">4. The Type System</a>\n  <a href=\"#judge-lawyer\">5. Judge &amp; Lawyer</a>\n  <a href=\"#crates\">6. Crate Map</a>\n  <a href=\"#principles\">7. Design Principles</a>\n  <a href=\"#glossary\">8. Glossary</a>\n</nav>\n\n<!-- ── Content ── -->\n<div class=\"content\">\n\n<!-- ════════════════════════════════════════════ -->\n<header id=\"intro\">\n  <h1>How tsz Works</h1>\n  <p class=\"page-subtitle\">An architectural guide for contributors</p>\n  <p class=\"page-description\">\n    tsz (Project Zang) is a TypeScript compiler written in Rust, targeting exact parity\n    with <code>tsc</code>. This document explains\n    how source code flows through the compiler, what data structures it produces at each\n    stage, and how the type system works internally. This document is source-grounded:\n    struct names, constant values, and function signatures are real. Where implementation\n    is still migrating toward the target architecture, sections below call out\n    <em>current state</em> versus <em>target state</em>.\n  </p>\n</header>\n\n<div class=\"callout\">\n  <div class=\"callout-title\">Current State vs Target State</div>\n  <p>\n    This page describes both the architecture target and the practical state of the codebase.\n    Some checker paths still contain transitional logic that is being moved behind solver\n    query boundaries.\n  </p>\n  <p>\n    Ongoing cleanup work is tracked in <code>docs/todos/architecture-purity.md</code>.\n  </p>\n</div>\n\n<!-- ════════════════════════════════════════════ -->\n<h2 id=\"pipeline\">1. The Pipeline at a Glance</h2>\n\n<p>\n  tsz compiles TypeScript through six sequential stages. Each stage has a single\n  responsibility, consumes the output of the previous stage, and is forbidden from\n  reaching backward into a previous stage's internals.\n</p>\n\n<div class=\"diagram\">\n<svg viewBox=\"0 0 820 100\" xmlns=\"http://www.w3.org/2000/svg\" role=\"img\" aria-label=\"Compiler pipeline: Scanner, Parser, Binder, Checker, Solver, Emitter\">\n  <style>\n    .box { rx: 6; ry: 6; stroke-width: 1.5; }\n    .box-text { font-family: -apple-system, sans-serif; font-size: 13px; font-weight: 600; text-anchor: middle; dominant-baseline: central; }\n    .arrow-line { stroke-width: 1.5; fill: none; marker-end: url(#ah); }\n    .sub-text { font-family: -apple-system, sans-serif; font-size: 9px; text-anchor: middle; dominant-baseline: central; }\n  </style>\n  <defs>\n    <marker id=\"ah\" markerWidth=\"7\" markerHeight=\"5\" refX=\"7\" refY=\"2.5\" orient=\"auto\">\n      <path d=\"M0,0 L7,2.5 L0,5\" fill=\"none\" stroke=\"var(--text-tertiary)\" stroke-width=\"1.2\"/>\n    </marker>\n  </defs>\n  <!-- Boxes -->\n  <rect x=\"10\" y=\"20\" width=\"105\" height=\"40\" class=\"box\" fill=\"var(--bg-subtle)\" stroke=\"var(--scanner-color)\"/>\n  <text x=\"62\" y=\"40\" class=\"box-text\" fill=\"var(--scanner-color)\">Scanner</text>\n  <text x=\"62\" y=\"72\" class=\"sub-text\" fill=\"var(--text-tertiary)\">~4K LOC</text>\n\n  <rect x=\"145\" y=\"20\" width=\"105\" height=\"40\" class=\"box\" fill=\"var(--bg-subtle)\" stroke=\"var(--parser-color)\"/>\n  <text x=\"197\" y=\"40\" class=\"box-text\" fill=\"var(--parser-color)\">Parser</text>\n  <text x=\"197\" y=\"72\" class=\"sub-text\" fill=\"var(--text-tertiary)\">~24K LOC</text>\n\n  <rect x=\"280\" y=\"20\" width=\"105\" height=\"40\" class=\"box\" fill=\"var(--bg-subtle)\" stroke=\"var(--binder-color)\"/>\n  <text x=\"332\" y=\"40\" class=\"box-text\" fill=\"var(--binder-color)\">Binder</text>\n  <text x=\"332\" y=\"72\" class=\"sub-text\" fill=\"var(--text-tertiary)\">~9K LOC</text>\n\n  <rect x=\"415\" y=\"20\" width=\"105\" height=\"40\" class=\"box\" fill=\"var(--bg-subtle)\" stroke=\"var(--checker-color)\"/>\n  <text x=\"467\" y=\"40\" class=\"box-text\" fill=\"var(--checker-color)\">Checker</text>\n  <text x=\"467\" y=\"72\" class=\"sub-text\" fill=\"var(--text-tertiary)\">~107K LOC</text>\n\n  <rect x=\"550\" y=\"20\" width=\"105\" height=\"40\" class=\"box\" fill=\"var(--bg-subtle)\" stroke=\"var(--solver-color)\"/>\n  <text x=\"602\" y=\"40\" class=\"box-text\" fill=\"var(--solver-color)\">Solver</text>\n  <text x=\"602\" y=\"72\" class=\"sub-text\" fill=\"var(--text-tertiary)\">~70K LOC</text>\n\n  <rect x=\"685\" y=\"20\" width=\"105\" height=\"40\" class=\"box\" fill=\"var(--bg-subtle)\" stroke=\"var(--emitter-color)\"/>\n  <text x=\"737\" y=\"40\" class=\"box-text\" fill=\"var(--emitter-color)\">Emitter</text>\n  <text x=\"737\" y=\"72\" class=\"sub-text\" fill=\"var(--text-tertiary)\">~54K LOC</text>\n\n  <!-- Arrows -->\n  <path d=\"M115,40 L145,40\" class=\"arrow-line\" stroke=\"var(--text-tertiary)\"/>\n  <path d=\"M250,40 L280,40\" class=\"arrow-line\" stroke=\"var(--text-tertiary)\"/>\n  <path d=\"M385,40 L415,40\" class=\"arrow-line\" stroke=\"var(--text-tertiary)\"/>\n  <path d=\"M520,40 L550,40\" class=\"arrow-line\" stroke=\"var(--text-tertiary)\"/>\n  <path d=\"M655,40 L685,40\" class=\"arrow-line\" stroke=\"var(--text-tertiary)\"/>\n\n  <!-- Bidirectional arrow for Checker-Solver -->\n  <path d=\"M510,30 C530,15 540,15 560,30\" class=\"arrow-line\" stroke=\"var(--text-tertiary)\" stroke-dasharray=\"3,2\" marker-end=\"none\"/>\n  <text x=\"535\" y=\"12\" class=\"sub-text\" fill=\"var(--text-tertiary)\">queries</text>\n</svg>\n</div>\n\n  <p>\n    The arrow between Checker and Solver is bidirectional in practice: the Checker walks\n    the AST and asks the Solver questions (\"is type A assignable to type B?\"), then the\n    Solver returns answers. The target architecture is that the Checker only decides\n    <em>where</em> to ask and how to report results. Current implementation still has\n    some checker-side semantic fast paths and narrowing logic while migration continues.\n  </p>\n\n<h3>Responsibility Matrix</h3>\n\n<p>\n  Every piece of code in the compiler should answer exactly one of these questions.\n  If you're unsure where something belongs, this table is the decision guide.\n</p>\n\n<table>\n  <thead>\n    <tr><th>Question</th><th>Stage</th><th>What it does</th></tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td><strong>WHO</strong> declares this?</td>\n      <td><span class=\"label binder\">Binder</span></td>\n      <td>Creates symbols, resolves scopes, builds the control-flow graph. Does not compute types.</td>\n    </tr>\n    <tr>\n      <td><strong>WHAT</strong> is the type?</td>\n      <td><span class=\"label solver\">Solver</span></td>\n      <td>Target owner of all type relations, inference, evaluation, instantiation, and narrowing. Migration in progress for remaining checker-side semantics.</td>\n    </tr>\n    <tr>\n      <td><strong>WHERE</strong> to report?</td>\n      <td><span class=\"label checker\">Checker</span></td>\n      <td>Walks the AST, picks the right diagnostic span, asks Solver for answers, emits diagnostics.</td>\n    </tr>\n    <tr>\n      <td><strong>OUTPUT</strong>?</td>\n      <td><span class=\"label emitter\">Emitter</span></td>\n      <td>Generates JavaScript and <code>.d.ts</code> declaration files. Should not own general semantic type validation.</td>\n    </tr>\n  </tbody>\n</table>\n\n<hr>\n\n<!-- ════════════════════════════════════════════ -->\n<h2 id=\"trace\">2. The Full Trace: <code>let x: string = 42</code></h2>\n\n<p>\n  To understand how the compiler works, let's follow a single line of TypeScript through\n  every stage. This example is simple but exercises the full pipeline: it declares a variable\n  with a type annotation and an initializer that doesn't match, producing a diagnostic.\n</p>\n\n<pre><code><span class=\"kw\">let</span> x: <span class=\"ty\">string</span> = <span class=\"num\">42</span>;</code></pre>\n\n<p>\n  This should produce: <code>TS2322: Type 'number' is not assignable to type 'string'</code>,\n  with the error span pointing at <code>42</code>. Here's exactly how that happens.\n</p>\n\n<!-- ── Step 1: Scanner ── -->\n<div class=\"trace-step scanner\" id=\"trace-scanner\">\n  <div class=\"step-label scanner\">Step 1 &mdash; Scanner</div>\n\n  <p>\n    The scanner (<code>tsz-scanner</code>) reads the source text character by character and\n    produces a stream of tokens. It is <strong>parser-driven</strong>: the parser calls\n    <code>scan()</code> to advance to the next token, rather than the scanner producing all\n    tokens eagerly.\n  </p>\n\n  <p>\n    As it scans, every identifier and string literal is <strong>interned</strong> into an\n    <code>Atom(u32)</code>. This means the string <code>\"x\"</code> is stored once in a global\n    table, and everywhere it appears in the program it's referenced by the same integer. String\n    comparison becomes integer comparison: O(1).\n  </p>\n\n  <p>For our input <code>let x: string = 42;</code>, the scanner produces:</p>\n\n  <table class=\"token-table\">\n    <thead>\n      <tr><th>Source</th><th>SyntaxKind</th><th>Value (u16)</th><th>Atom</th></tr>\n    </thead>\n    <tbody>\n      <tr><td><code>let</code></td><td>LetKeyword</td><td>121</td><td>&mdash; (keyword)</td></tr>\n      <tr><td><code>x</code></td><td>Identifier</td><td>80</td><td>Atom(47)*</td></tr>\n      <tr><td><code>:</code></td><td>ColonToken</td><td>59</td><td>&mdash;</td></tr>\n      <tr><td><code>string</code></td><td>StringKeyword</td><td>154</td><td>&mdash; (keyword)</td></tr>\n      <tr><td><code>=</code></td><td>EqualsToken</td><td>64</td><td>&mdash;</td></tr>\n      <tr><td><code>42</code></td><td>NumericLiteral</td><td>9</td><td>&mdash;</td></tr>\n      <tr><td><code>;</code></td><td>SemicolonToken</td><td>27</td><td>&mdash;</td></tr>\n    </tbody>\n  </table>\n\n  <div class=\"callout\">\n    <div class=\"callout-title\">Note</div>\n    <p>\n      *Atom values are assigned sequentially at runtime and depend on what strings have been\n      interned before. The value 47 is illustrative. Keywords like <code>let</code> and\n      <code>string</code> are recognized by the scanner directly and don't need atom interning\n      for identity&mdash;their SyntaxKind already distinguishes them.\n    </p>\n  </div>\n\n  <p>\n    The scanner also tracks position spans. Each token carries a <code>start</code> and\n    <code>end</code> byte offset into the source. For <code>42</code>, that would be\n    <code>start=18, end=20</code>. These positions flow through the entire pipeline and\n    are ultimately used by the Checker to produce the diagnostic's source location.\n  </p>\n</div>\n\n<!-- ── Step 2: Parser ── -->\n<div class=\"trace-step parser\" id=\"trace-parser\">\n  <div class=\"step-label parser\">Step 2 &mdash; Parser</div>\n\n  <p>\n    The parser (<code>tsz-parser</code>) consumes tokens and builds an Abstract Syntax Tree\n    in a <code>NodeArena</code>. It performs <strong>no semantic analysis</strong>&mdash;it\n    doesn't know what types are, it doesn't resolve names, and it doesn't report type errors.\n    It only cares about syntactic structure.\n  </p>\n\n  <p>For our input, the parser produces this AST:</p>\n\n  <div class=\"diagram\">\n  <svg viewBox=\"0 0 600 240\" xmlns=\"http://www.w3.org/2000/svg\" role=\"img\" aria-label=\"AST tree for let x: string = 42\">\n    <style>\n      .ast-box { rx: 4; ry: 4; stroke-width: 1; }\n      .ast-text { font-family: -apple-system, sans-serif; font-size: 11px; font-weight: 600; text-anchor: middle; dominant-baseline: central; }\n      .ast-sub { font-family: monospace; font-size: 9px; text-anchor: middle; dominant-baseline: central; }\n      .ast-line { stroke-width: 1; }\n    </style>\n    <!-- VariableStatement -->\n    <rect x=\"220\" y=\"10\" width=\"160\" height=\"30\" class=\"ast-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--parser-color)\"/>\n    <text x=\"300\" y=\"25\" class=\"ast-text\" fill=\"var(--parser-color)\">VariableStatement</text>\n    <text x=\"300\" y=\"48\" class=\"ast-sub\" fill=\"var(--text-tertiary)\">kind=244</text>\n\n    <!-- Line to DeclList -->\n    <line x1=\"300\" y1=\"40\" x2=\"300\" y2=\"70\" class=\"ast-line\" stroke=\"var(--border)\"/>\n\n    <!-- VariableDeclarationList -->\n    <rect x=\"195\" y=\"70\" width=\"210\" height=\"30\" class=\"ast-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--parser-color)\"/>\n    <text x=\"300\" y=\"85\" class=\"ast-text\" fill=\"var(--parser-color)\">VariableDeclarationList</text>\n    <text x=\"300\" y=\"108\" class=\"ast-sub\" fill=\"var(--text-tertiary)\">kind=262, flags=LET</text>\n\n    <!-- Line to Declaration -->\n    <line x1=\"300\" y1=\"100\" x2=\"300\" y2=\"130\" class=\"ast-line\" stroke=\"var(--border)\"/>\n\n    <!-- VariableDeclaration -->\n    <rect x=\"200\" y=\"130\" width=\"200\" height=\"30\" class=\"ast-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--parser-color)\"/>\n    <text x=\"300\" y=\"145\" class=\"ast-text\" fill=\"var(--parser-color)\">VariableDeclaration</text>\n    <text x=\"300\" y=\"168\" class=\"ast-sub\" fill=\"var(--text-tertiary)\">kind=261</text>\n\n    <!-- Three children -->\n    <line x1=\"250\" y1=\"160\" x2=\"100\" y2=\"190\" class=\"ast-line\" stroke=\"var(--border)\"/>\n    <line x1=\"300\" y1=\"160\" x2=\"300\" y2=\"190\" class=\"ast-line\" stroke=\"var(--border)\"/>\n    <line x1=\"350\" y1=\"160\" x2=\"500\" y2=\"190\" class=\"ast-line\" stroke=\"var(--border)\"/>\n\n    <!-- Identifier \"x\" -->\n    <rect x=\"40\" y=\"190\" width=\"120\" height=\"30\" class=\"ast-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--text-tertiary)\"/>\n    <text x=\"100\" y=\"205\" class=\"ast-text\" fill=\"var(--text)\">Identifier \"x\"</text>\n\n    <!-- TypeReference \"string\" -->\n    <rect x=\"215\" y=\"190\" width=\"170\" height=\"30\" class=\"ast-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--text-tertiary)\"/>\n    <text x=\"300\" y=\"205\" class=\"ast-text\" fill=\"var(--text)\">TypeReference \"string\"</text>\n\n    <!-- NumericLiteral 42 -->\n    <rect x=\"430\" y=\"190\" width=\"140\" height=\"30\" class=\"ast-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--text-tertiary)\"/>\n    <text x=\"500\" y=\"205\" class=\"ast-text\" fill=\"var(--text)\">NumericLiteral 42</text>\n\n    <!-- Labels -->\n    <text x=\"60\" y=\"183\" class=\"ast-sub\" fill=\"var(--text-tertiary)\">name</text>\n    <text x=\"270\" y=\"183\" class=\"ast-sub\" fill=\"var(--text-tertiary)\">type</text>\n    <text x=\"470\" y=\"183\" class=\"ast-sub\" fill=\"var(--text-tertiary)\">initializer</text>\n  </svg>\n  </div>\n\n  <h4>The 16-byte node header</h4>\n\n  <p>\n    Every AST node in the arena has a fixed-size 16-byte header. This is critical for\n    performance: four nodes fit in a single 64-byte cache line, and the header is\n    small enough that the CPU prefetcher works efficiently.\n  </p>\n\n  <div class=\"node-layout\">\n    <div class=\"cell\"><span class=\"cell-label\">kind</span><span class=\"cell-size\">u16 &middot; 2B</span></div>\n    <div class=\"cell\"><span class=\"cell-label\">flags</span><span class=\"cell-size\">u16 &middot; 2B</span></div>\n    <div class=\"cell\"><span class=\"cell-label\">pos</span><span class=\"cell-size\">u32 &middot; 4B</span></div>\n    <div class=\"cell\"><span class=\"cell-label\">end</span><span class=\"cell-size\">u32 &middot; 4B</span></div>\n  </div>\n  <div class=\"node-layout\" style=\"grid-template-columns: 1fr;\">\n    <div class=\"cell\"><span class=\"cell-label\">data_index</span><span class=\"cell-size\">u32 &middot; 4B &mdash; index into typed side pool (u32::MAX = no data)</span></div>\n  </div>\n\n  <p>\n    Variable-sized payloads (child node lists, string data, etc.) are stored in\n    <strong>typed side pools</strong> indexed by <code>data_index</code>. There are 40+\n    pool types: one for identifiers, one for binary expressions, one for call expressions,\n    and so on. This keeps the hot node array compact while allowing heterogeneous payloads.\n  </p>\n</div>\n\n<!-- ── Step 3: Binder ── -->\n<div class=\"trace-step binder\" id=\"trace-binder\">\n  <div class=\"step-label binder\">Step 3 &mdash; Binder</div>\n\n  <p>\n    The binder (<code>tsz-binder</code>) walks the AST and builds three things: a\n    <strong>symbol table</strong>, a <strong>scope tree</strong>, and a <strong>control-flow\n    graph</strong>. It answers the question \"WHO declares this name?\" without doing any\n    type computation.\n  </p>\n\n  <p>For our variable declaration <code>let x</code>, the binder:</p>\n\n  <ol>\n    <li>\n      Creates a new symbol in the symbol arena: <code>SymbolId(5)</code> (the exact index\n      depends on how many symbols have been created before).\n    </li>\n    <li>\n      Sets the symbol's flags to <code>BLOCK_SCOPED_VARIABLE</code> (bit 1, value <code>0x2</code>)\n      because <code>let</code> is block-scoped.\n    </li>\n    <li>\n      Records the declaration: the symbol's <code>value_declaration</code> points back to the\n      VariableDeclaration AST node.\n    </li>\n    <li>\n      Registers the symbol in the current scope's symbol table under the name <code>\"x\"</code>\n      (stored as an <code>Atom</code>).\n    </li>\n    <li>\n      Creates a flow node (<code>FlowNodeId</code>) for the assignment, linking it to the\n      previous flow state via an antecedent chain.\n    </li>\n  </ol>\n\n  <pre><code><span class=\"cm\">// What the binder produces for `let x: string = 42`</span>\nSymbol {\n    flags: <span class=\"num\">0x2</span>,              <span class=\"cm\">// BLOCK_SCOPED_VARIABLE</span>\n    escaped_name: <span class=\"str\">\"x\"</span>,       <span class=\"cm\">// Atom-interned</span>\n    declarations: [NodeIndex(<span class=\"num\">3</span>)],  <span class=\"cm\">// the VariableDeclaration node</span>\n    value_declaration: NodeIndex(<span class=\"num\">3</span>),\n    parent: SymbolId(<span class=\"num\">0</span>),     <span class=\"cm\">// source file symbol</span>\n}</code></pre>\n\n  <div class=\"callout\">\n    <div class=\"callout-title\">Key rule</div>\n    <p>\n      The binder does <strong>no type computation</strong>. It does not look at the type\n      annotation <code>string</code> or the initializer <code>42</code> for type information.\n      It only records that a symbol named <code>x</code> exists, where it was declared, and\n      what scope it belongs to. Types are computed later by the Checker and Solver.\n    </p>\n  </div>\n\n  <h4>The scope tree</h4>\n\n  <p>\n    Scopes are stored as a persistent tree (not a stack). Each scope has a parent pointer,\n    so the compiler can look up names by walking from the current scope toward the root.\n    For a simple file-level declaration like this one, <code>x</code> lives in the source\n    file scope directly.\n  </p>\n\n  <h4>The control-flow graph</h4>\n\n  <p>\n    The binder also constructs a flow graph used later for type narrowing. For our simple\n    assignment, it creates an ASSIGNMENT flow node. In more complex code (if/else, loops,\n    type guards), the flow graph tracks which branches are reachable and what type\n    narrowings apply.\n  </p>\n</div>\n\n<!-- ── Step 4: Checker ── -->\n<div class=\"trace-step checker\" id=\"trace-checker\">\n  <div class=\"step-label checker\">Step 4 &mdash; Checker</div>\n\n  <p>\n    The checker (<code>tsz-checker</code>) is the orchestrator. It walks the AST top-down,\n    and when it reaches our VariableDeclaration node, it performs these steps:\n  </p>\n\n  <ol>\n    <li>\n      <strong>Resolve the type annotation.</strong> The type annotation is a TypeReference node\n      pointing to <code>string</code>. The checker resolves this to the built-in type\n      <code>TypeId::STRING</code>, which is a compile-time constant <code>TypeId(10)</code>.\n    </li>\n    <li>\n      <strong>Get the initializer's type.</strong> The initializer is the numeric literal\n      <code>42</code>. The checker calls <code>get_type_of_node()</code> on it, which\n      (via the lowering layer) interns the literal type into the solver: the number type\n      <code>TypeId::NUMBER</code> = <code>TypeId(9)</code>.\n    </li>\n    <li>\n      <strong>Check assignability.</strong> The checker now asks the Solver: \"is\n      <code>TypeId(9)</code> (number) assignable to <code>TypeId(10)</code> (string)?\"\n      This goes through the <code>query_boundaries</code> assignability gateway.\n    </li>\n    <li>\n      <strong>Handle the result.</strong> The Solver returns \"not assignable\" with a\n      structured failure reason. The checker uses this to produce the diagnostic.\n    </li>\n  </ol>\n\n  <pre><code><span class=\"cm\">// Pseudocode of what the checker does</span>\n<span class=\"kw\">fn</span> <span class=\"fn\">check_variable_declaration</span>(node: VariableDeclaration) {\n    <span class=\"kw\">let</span> declared_type = <span class=\"fn\">resolve_type_annotation</span>(node.type);  <span class=\"cm\">// TypeId(10) = STRING</span>\n    <span class=\"kw\">let</span> init_type = <span class=\"fn\">get_type_of_node</span>(node.initializer);     <span class=\"cm\">// TypeId(9)  = NUMBER</span>\n\n    <span class=\"cm\">// Ask Solver via query_boundaries gateway</span>\n    <span class=\"kw\">if</span> !<span class=\"fn\">is_type_assignable_to</span>(init_type, declared_type) {\n        <span class=\"kw\">let</span> reason = <span class=\"fn\">get_assignability_failure</span>(init_type, declared_type);\n        <span class=\"fn\">emit_diagnostic</span>(\n            TS2322,\n            node.initializer.span(),  <span class=\"cm\">// point at `42`</span>\n            reason,\n        );\n    }\n}</code></pre>\n\n  <div class=\"callout\">\n    <div class=\"callout-title\">Architecture rule</div>\n    <p>\n      The checker never matches on <code>TypeKey</code> variants or does structural type\n      comparison itself. It asks the Solver and trusts the answer. If you find yourself\n      writing <code>match types.lookup(type_id) { ... }</code> in checker code, that logic\n      belongs in the Solver.\n    </p>\n  </div>\n</div>\n\n<!-- ── Step 5: Solver ── -->\n<div class=\"trace-step solver\" id=\"trace-solver\">\n  <div class=\"step-label solver\">Step 5 &mdash; Solver</div>\n\n  <p>\n    The solver (<code>tsz-solver</code>) is where the actual type computation happens. When\n    the checker asks \"is <code>TypeId(9)</code> assignable to <code>TypeId(10)</code>?\", the\n    solver runs its assignability algorithm:\n  </p>\n\n  <ol>\n    <li>\n      <strong>Identity check.</strong> Is <code>TypeId(9) == TypeId(10)</code>? No\n      (9 &ne; 10). This is a single integer comparison&mdash;O(1).\n    </li>\n    <li>\n      <strong>Top/bottom check.</strong> Is the source <code>never</code> (assignable to\n      everything)? No. Is the target <code>unknown</code> (accepts everything)? No.\n    </li>\n    <li>\n      <strong>Structural check.</strong> Look up the actual type data. <code>TypeId(9)</code>\n      resolves to <code>Intrinsic(Number)</code>. <code>TypeId(10)</code> resolves to\n      <code>Intrinsic(String)</code>. Two different intrinsic types with no subtype\n      relationship.\n    </li>\n    <li>\n      <strong>Result: not assignable.</strong> The solver returns <code>false</code> and\n      produces a structured failure reason that the checker will use for the diagnostic message.\n    </li>\n  </ol>\n\n  <pre><code><span class=\"cm\">// Solver's assignability check (simplified)</span>\n<span class=\"kw\">fn</span> <span class=\"fn\">is_assignable_to</span>(source: <span class=\"ty\">TypeId</span>, target: <span class=\"ty\">TypeId</span>) -> <span class=\"ty\">bool</span> {\n    <span class=\"cm\">// 1. Identity: same TypeId? Done.</span>\n    <span class=\"kw\">if</span> source == target { <span class=\"kw\">return</span> <span class=\"num\">true</span>; }\n\n    <span class=\"cm\">// 2. Top/bottom short-circuits</span>\n    <span class=\"kw\">if</span> source == <span class=\"ty\">TypeId</span>::NEVER { <span class=\"kw\">return</span> <span class=\"num\">true</span>; }\n    <span class=\"kw\">if</span> target == <span class=\"ty\">TypeId</span>::UNKNOWN { <span class=\"kw\">return</span> <span class=\"num\">true</span>; }\n\n    <span class=\"cm\">// 3. Structural comparison</span>\n    <span class=\"kw\">match</span> (lookup(source), lookup(target)) {\n        (<span class=\"ty\">Intrinsic</span>(Number), <span class=\"ty\">Intrinsic</span>(String)) => <span class=\"num\">false</span>,  <span class=\"cm\">// our case</span>\n        <span class=\"cm\">// ... hundreds of other structural rules</span>\n    }\n}</code></pre>\n\n  <p>\n    For more complex cases (unions, intersections, generics, conditional types), the solver\n    uses <strong>coinductive semantics</strong> with a cycle stack to handle recursive types,\n    and <strong>memoization</strong> to avoid re-checking the same type pair. Depth limits\n    prevent runaway checks: max subtype depth is 100, max total checks per compilation is\n    100,000.\n  </p>\n</div>\n\n<!-- ── Step 6: Diagnostic ── -->\n<div class=\"trace-step diagnostic\" id=\"trace-diagnostic\">\n  <div class=\"step-label diagnostic\">Step 6 &mdash; Diagnostic Output</div>\n\n  <p>\n    The checker takes the solver's failure reason and renders the final diagnostic. It\n    selects the error span (pointing at the initializer <code>42</code>, not the whole\n    declaration), formats the type names, and produces:\n  </p>\n\n  <pre><code>error <span class=\"kw\">TS2322</span>: Type '<span class=\"ty\">number</span>' is not assignable to type '<span class=\"ty\">string</span>'.\n\n  <span class=\"kw\">let</span> x: <span class=\"ty\">string</span> = <span class=\"num\">42</span>;\n                    <span class=\"kw\">~~</span></code></pre>\n\n  <p>\n    The diagnostic includes the error code (TS2322), the file path, the line and column,\n    and the message. This must match <code>tsc</code> exactly&mdash;same code, same span,\n    same message text&mdash;for the conformance test to pass.\n  </p>\n\n  <div class=\"callout\">\n    <div class=\"callout-title\">The TS2322 pipeline</div>\n    <p>\n      TS2322 (\"Type 'X' is not assignable to type 'Y'\") is the most common diagnostic.\n      Its path is strictly controlled: <strong>relation first</strong> (Solver determines\n      assignability), <strong>reason second</strong> (Solver explains why), <strong>location\n      last</strong> (Checker picks the span and formats the message). New TS2322/TS2345/TS2416\n      work must go through the <code>query_boundaries</code> assignability gateway, and\n      remaining legacy call sites are being migrated.\n    </p>\n  </div>\n</div>\n\n<hr>\n\n<!-- ════════════════════════════════════════════ -->\n<h2 id=\"memory\">3. Memory Architecture</h2>\n\n<p>\n  tsz uses <strong>arena allocation</strong> for all major data structures. Instead of\n  allocating each AST node, symbol, or type on the heap individually, data is stored\n  in contiguous arrays and referenced by lightweight <code>u32</code> handles. This\n  eliminates fragmentation, enables O(1) access, and plays well with CPU caches.\n</p>\n\n<h3>Identity Handles</h3>\n\n<p>\n  Every major entity in the compiler has a <code>u32</code>-based identity handle. This\n  is the fundamental performance trick: comparing two types, two symbols, or two strings\n  is always a single integer comparison.\n</p>\n\n<table>\n  <thead>\n    <tr><th>Handle</th><th>Definition</th><th>Lives in</th><th>Purpose</th></tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td><code>TypeId(u32)</code></td>\n      <td>Index into TypeInterner</td>\n      <td>tsz-solver</td>\n      <td>Type identity. IDs 0&ndash;99 reserved for built-ins. O(1) equality.</td>\n    </tr>\n    <tr>\n      <td><code>SymbolId(u32)</code></td>\n      <td>Index into SymbolArena</td>\n      <td>tsz-binder</td>\n      <td>Symbol identity. Every variable, function, class gets one.</td>\n    </tr>\n    <tr>\n      <td><code>Atom(u32)</code></td>\n      <td>Index into Interner</td>\n      <td>tsz-common</td>\n      <td>Interned string. All identifiers and strings deduplicated.</td>\n    </tr>\n    <tr>\n      <td><code>FlowNodeId(u32)</code></td>\n      <td>Index into FlowNodeArena</td>\n      <td>tsz-binder</td>\n      <td>Control-flow graph node. Used for type narrowing.</td>\n    </tr>\n    <tr>\n      <td><code>NodeIndex</code></td>\n      <td>Index into NodeArena</td>\n      <td>tsz-parser</td>\n      <td>AST node reference. Points to a 16-byte node header.</td>\n    </tr>\n  </tbody>\n</table>\n\n<h3>Arena Layout</h3>\n\n<pre><code><span class=\"cm\">// Memory layout (conceptual)</span>\n\nNodeArena         [Node][Node][Node][Node][Node]...     <span class=\"cm\">// 16 bytes each, contiguous</span>\n                      |     |     |\nIdentifierPool    [IdentData][IdentData]...             <span class=\"cm\">// typed side pool</span>\nCallExprPool      [CallData][CallData]...               <span class=\"cm\">// typed side pool</span>\n  ...               (40+ pools)\n\nSymbolArena       [Symbol][Symbol][Symbol]...            <span class=\"cm\">// indexed by SymbolId</span>\nFlowNodeArena     [FlowNode][FlowNode]...               <span class=\"cm\">// indexed by FlowNodeId</span>\n\nTypeInterner      [TypeData][TypeData][TypeData]...      <span class=\"cm\">// indexed by TypeId</span>\n                  HashMap&lt;TypeData, TypeId&gt;              <span class=\"cm\">// dedup: same structure = same ID</span>\n\nStringInterner    [<span class=\"str\">\"x\"</span>][<span class=\"str\">\"string\"</span>][<span class=\"str\">\"number\"</span>]...         <span class=\"cm\">// indexed by Atom</span>\n                  HashMap&lt;&amp;str, Atom&gt;                    <span class=\"cm\">// dedup: same string = same Atom</span></code></pre>\n\n<h3>Built-in TypeIds</h3>\n\n<p>\n  The first 100 TypeIds are reserved for built-in types. These are compile-time constants,\n  so checking \"is this type <code>string</code>?\" is just <code>type_id == TypeId(10)</code>.\n</p>\n\n<table>\n  <thead>\n    <tr><th>TypeId</th><th>Value</th><th>Type</th></tr>\n  </thead>\n  <tbody>\n    <tr><td><code>TypeId(0)</code></td><td>NONE</td><td>Sentinel / uninitialized</td></tr>\n    <tr><td><code>TypeId(1)</code></td><td>ERROR</td><td>Error recovery type</td></tr>\n    <tr><td><code>TypeId(2)</code></td><td>NEVER</td><td>Bottom type (assignable to everything)</td></tr>\n    <tr><td><code>TypeId(3)</code></td><td>UNKNOWN</td><td>Top type (accepts everything)</td></tr>\n    <tr><td><code>TypeId(4)</code></td><td>ANY</td><td>TypeScript's escape hatch</td></tr>\n    <tr><td><code>TypeId(5)</code></td><td>VOID</td><td>void</td></tr>\n    <tr><td><code>TypeId(6)</code></td><td>UNDEFINED</td><td>undefined</td></tr>\n    <tr><td><code>TypeId(7)</code></td><td>NULL</td><td>null</td></tr>\n    <tr><td><code>TypeId(8)</code></td><td>BOOLEAN</td><td>boolean</td></tr>\n    <tr><td><code>TypeId(9)</code></td><td>NUMBER</td><td>number</td></tr>\n    <tr><td><code>TypeId(10)</code></td><td>STRING</td><td>string</td></tr>\n    <tr><td><code>TypeId(11)</code></td><td>BIGINT</td><td>bigint</td></tr>\n    <tr><td><code>TypeId(12)</code></td><td>SYMBOL</td><td>symbol</td></tr>\n    <tr><td><code>TypeId(13)</code></td><td>OBJECT</td><td>object</td></tr>\n    <tr><td><code>TypeId(14)</code></td><td>BOOLEAN_TRUE</td><td>Literal <code>true</code></td></tr>\n    <tr><td><code>TypeId(15)</code></td><td>BOOLEAN_FALSE</td><td>Literal <code>false</code></td></tr>\n    <tr><td><code>TypeId(16)</code></td><td>FUNCTION</td><td>Function</td></tr>\n    <tr><td><code>TypeId(100+)</code></td><td>FIRST_USER</td><td>User-defined types start here</td></tr>\n  </tbody>\n</table>\n\n<hr>\n\n<!-- ════════════════════════════════════════════ -->\n<h2 id=\"types\">4. The Type System</h2>\n\n<p>\n  The Solver represents every TypeScript type as a <code>TypeData</code> variant, interned\n  into the global <code>TypeInterner</code>. When two different parts of the program create\n  the same type, the interner returns the same <code>TypeId</code>. This deduplication means\n  the compiler never has two copies of the same type in memory, and equality is always O(1).\n</p>\n\n<h3>TypeData Variants</h3>\n\n<p>\n  The full <code>TypeData</code> (internally <code>TypeKey</code>) enum covers the complete\n  TypeScript type surface:\n</p>\n\n<table>\n  <thead>\n    <tr><th>Variant</th><th>TypeScript Example</th><th>Description</th></tr>\n  </thead>\n  <tbody>\n    <tr><td><code>Intrinsic</code></td><td><code>string</code>, <code>number</code>, <code>any</code></td><td>Primitive and special types</td></tr>\n    <tr><td><code>Literal</code></td><td><code>\"hello\"</code>, <code>42</code>, <code>true</code></td><td>Literal types (string/number/boolean/bigint)</td></tr>\n    <tr><td><code>Object</code></td><td><code>{ x: number, y: string }</code></td><td>Structural object types</td></tr>\n    <tr><td><code>Union</code></td><td><code>string | number</code></td><td>Union of types</td></tr>\n    <tr><td><code>Intersection</code></td><td><code>A &amp; B</code></td><td>Intersection of types</td></tr>\n    <tr><td><code>Array</code></td><td><code>number[]</code></td><td>Array types</td></tr>\n    <tr><td><code>Tuple</code></td><td><code>[string, number]</code></td><td>Tuple types (with optional/rest)</td></tr>\n    <tr><td><code>Function</code></td><td><code>(x: number) =&gt; string</code></td><td>Single-signature callable</td></tr>\n    <tr><td><code>Callable</code></td><td>Overloaded function</td><td>Multiple call signatures</td></tr>\n    <tr><td><code>TypeParameter</code></td><td><code>T extends Constraint</code></td><td>Generic type parameters</td></tr>\n    <tr><td><code>Lazy(DefId)</code></td><td>Forward reference</td><td>Deferred resolution; avoids cycles</td></tr>\n    <tr><td><code>Application</code></td><td><code>Map&lt;string, number&gt;</code></td><td>Generic type application</td></tr>\n    <tr><td><code>Conditional</code></td><td><code>T extends U ? X : Y</code></td><td>Conditional types</td></tr>\n    <tr><td><code>Mapped</code></td><td><code>{ [K in keyof T]: V }</code></td><td>Mapped types</td></tr>\n    <tr><td><code>IndexAccess</code></td><td><code>T[K]</code></td><td>Indexed access types</td></tr>\n    <tr><td><code>KeyOf</code></td><td><code>keyof T</code></td><td>Key-of operator</td></tr>\n    <tr><td><code>TemplateLiteral</code></td><td><code>`hello ${T}`</code></td><td>Template literal types</td></tr>\n    <tr><td><code>Infer</code></td><td><code>infer R</code></td><td>Inference variable in conditional types</td></tr>\n    <tr><td><code>Error</code></td><td>&mdash;</td><td>Error recovery; silences cascading diagnostics</td></tr>\n  </tbody>\n</table>\n\n<h3>Concrete Example</h3>\n\n<p>Consider this TypeScript:</p>\n\n<pre><code><span class=\"kw\">interface</span> <span class=\"ty\">User</span> {\n  name: <span class=\"ty\">string</span>;\n  age: <span class=\"ty\">number</span>;\n}\n<span class=\"kw\">type</span> <span class=\"ty\">Admin</span> = <span class=\"ty\">User</span> &amp; { role: <span class=\"str\">\"admin\"</span> };</code></pre>\n\n<p>The solver interns these as:</p>\n\n<pre><code><span class=\"cm\">// User becomes an Object type</span>\n<span class=\"ty\">TypeId</span>(<span class=\"num\">102</span>) = Object {\n    properties: [\n        (<span class=\"str\">\"name\"</span>, <span class=\"ty\">TypeId::STRING</span>),    <span class=\"cm\">// TypeId(10)</span>\n        (<span class=\"str\">\"age\"</span>,  <span class=\"ty\">TypeId::NUMBER</span>),    <span class=\"cm\">// TypeId(9)</span>\n    ]\n}\n\n<span class=\"cm\">// { role: \"admin\" } becomes another Object type</span>\n<span class=\"ty\">TypeId</span>(<span class=\"num\">103</span>) = Object {\n    properties: [\n        (<span class=\"str\">\"role\"</span>, <span class=\"ty\">TypeId</span>(<span class=\"num\">104</span>)),       <span class=\"cm\">// Literal(\"admin\")</span>\n    ]\n}\n\n<span class=\"cm\">// Admin = User & { role: \"admin\" }</span>\n<span class=\"ty\">TypeId</span>(<span class=\"num\">105</span>) = Intersection([<span class=\"ty\">TypeId</span>(<span class=\"num\">102</span>), <span class=\"ty\">TypeId</span>(<span class=\"num\">103</span>)])</code></pre>\n\n<h3>Lazy Resolution and DefId</h3>\n\n<p>\n  Types can reference each other circularly (e.g., a linked list node that contains a\n  pointer to another node of the same type). To avoid infinite loops during type construction,\n  the Solver uses <code>Lazy(DefId)</code> as a placeholder. A <code>DefId</code> is a\n  stable identifier for a type definition. The <code>TypeEnvironment</code> resolves\n  <code>DefId &rarr; TypeId</code> on demand during relation checks and evaluation.\n</p>\n\n<p>\n  This is the same pattern as lazy evaluation in functional languages: don't compute the\n  type until someone actually asks for it, and when they do, cache the result.\n</p>\n\n<hr>\n\n<!-- ════════════════════════════════════════════ -->\n<h2 id=\"judge-lawyer\">5. The Judge &amp; Lawyer Model</h2>\n\n<p>\n  TypeScript is intentionally unsound. It allows things like bivariant function parameters,\n  <code>any</code> silencing structural mismatches, and excess property checking that depends\n  on object literal \"freshness.\" These aren't bugs&mdash;they're deliberate design choices\n  that make the language more ergonomic at the cost of type safety.\n</p>\n\n<p>\n  tsz separates these concerns into two layers:\n</p>\n\n<h3>The Judge: <code>SubtypeChecker</code></h3>\n\n<p>\n  The Judge implements <strong>strict structural subtyping</strong> based on set theory.\n  It knows nothing about TypeScript's legacy quirks. Given two types, it determines whether\n  one is structurally a subtype of the other using only mathematical rules: covariance for\n  properties, contravariance for function parameters, width subtyping for objects.\n</p>\n\n<p>\n  If the Judge says \"not a subtype,\" it provides a structured failure reason explaining\n  exactly which property or parameter caused the mismatch.\n</p>\n\n<h3>The Lawyer: <code>CompatChecker</code> + <code>AnyPropagationRules</code></h3>\n\n<p>\n  The Lawyer takes the Judge's strict answer and applies TypeScript-specific compatibility\n  rules. These are the places where <code>tsc</code> intentionally deviates from soundness:\n</p>\n\n<table>\n  <thead>\n    <tr><th>Quirk</th><th>Judge (Sound)</th><th>Lawyer (tsc-Compatible)</th></tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td><code>any</code> assignability</td>\n      <td>Treated as strict set</td>\n      <td>Both top and bottom type (assignable to and from everything)</td>\n    </tr>\n    <tr>\n      <td>Function params</td>\n      <td>Contravariant</td>\n      <td>Bivariant for methods (strictFunctionTypes=false)</td>\n    </tr>\n    <tr>\n      <td>Object literals</td>\n      <td>Width subtyping (extra props OK)</td>\n      <td>Excess property check on \"fresh\" literals</td>\n    </tr>\n    <tr>\n      <td>Void returns</td>\n      <td>Normal checking</td>\n      <td><code>() =&gt; void</code> accepts any return type</td>\n    </tr>\n    <tr>\n      <td>Weak types (TS2559)</td>\n      <td>Normal structural check</td>\n      <td>Objects with only optional properties require at least one overlap</td>\n    </tr>\n  </tbody>\n</table>\n\n<p>\n  This separation means tsz can reason about <em>actual</em> type safety (what the Judge\n  thinks) while still producing the same diagnostics as <code>tsc</code> (what the Lawyer\n  decides after applying compatibility rules). It also makes it possible to implement a\n  hypothetical \"strict mode\" in the future that uses only the Judge.\n</p>\n\n<hr>\n\n<!-- ════════════════════════════════════════════ -->\n<h2 id=\"crates\">6. Crate Map</h2>\n\n<p>\n  tsz is organized as a Cargo workspace with 12 crates. The dependency direction is\n  strictly one-way: downstream crates depend on upstream ones, never the reverse. This\n  is enforced by CI.\n</p>\n\n<h3>Dependency Graph</h3>\n\n<div class=\"diagram\">\n<svg viewBox=\"0 0 640 420\" xmlns=\"http://www.w3.org/2000/svg\" role=\"img\" aria-label=\"Crate dependency graph\">\n  <style>\n    .crate-box { rx: 5; ry: 5; stroke-width: 1.2; }\n    .crate-text { font-family: monospace; font-size: 11px; font-weight: 600; text-anchor: middle; dominant-baseline: central; }\n    .dep-line { stroke-width: 1; fill: none; }\n  </style>\n  <defs>\n    <marker id=\"dep-arrow\" markerWidth=\"6\" markerHeight=\"5\" refX=\"6\" refY=\"2.5\" orient=\"auto\">\n      <path d=\"M0,0 L6,2.5 L0,5\" fill=\"none\" stroke=\"var(--text-tertiary)\" stroke-width=\"1\"/>\n    </marker>\n  </defs>\n\n  <!-- Layer 0: common -->\n  <rect x=\"250\" y=\"10\" width=\"140\" height=\"30\" class=\"crate-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--scanner-color)\"/>\n  <text x=\"320\" y=\"25\" class=\"crate-text\" fill=\"var(--scanner-color)\">tsz-common</text>\n\n  <!-- Layer 1: scanner, parser -->\n  <rect x=\"100\" y=\"80\" width=\"130\" height=\"30\" class=\"crate-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--scanner-color)\"/>\n  <text x=\"165\" y=\"95\" class=\"crate-text\" fill=\"var(--scanner-color)\">tsz-scanner</text>\n\n  <rect x=\"270\" y=\"80\" width=\"130\" height=\"30\" class=\"crate-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--parser-color)\"/>\n  <text x=\"335\" y=\"95\" class=\"crate-text\" fill=\"var(--parser-color)\">tsz-parser</text>\n\n  <!-- Layer 2: binder, solver, lowering -->\n  <rect x=\"80\" y=\"160\" width=\"130\" height=\"30\" class=\"crate-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--binder-color)\"/>\n  <text x=\"145\" y=\"175\" class=\"crate-text\" fill=\"var(--binder-color)\">tsz-binder</text>\n\n  <rect x=\"250\" y=\"160\" width=\"130\" height=\"30\" class=\"crate-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--solver-color)\"/>\n  <text x=\"315\" y=\"175\" class=\"crate-text\" fill=\"var(--solver-color)\">tsz-solver</text>\n\n  <rect x=\"420\" y=\"160\" width=\"140\" height=\"30\" class=\"crate-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--text-tertiary)\"/>\n  <text x=\"490\" y=\"175\" class=\"crate-text\" fill=\"var(--text-secondary)\">tsz-lowering</text>\n\n  <!-- Layer 3: checker -->\n  <rect x=\"230\" y=\"240\" width=\"140\" height=\"30\" class=\"crate-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--checker-color)\"/>\n  <text x=\"300\" y=\"255\" class=\"crate-text\" fill=\"var(--checker-color)\">tsz-checker</text>\n\n  <!-- Layer 4: emitter, cli, lsp, wasm -->\n  <rect x=\"30\" y=\"320\" width=\"130\" height=\"30\" class=\"crate-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--emitter-color)\"/>\n  <text x=\"95\" y=\"335\" class=\"crate-text\" fill=\"var(--emitter-color)\">tsz-emitter</text>\n\n  <rect x=\"190\" y=\"320\" width=\"100\" height=\"30\" class=\"crate-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--text-tertiary)\"/>\n  <text x=\"240\" y=\"335\" class=\"crate-text\" fill=\"var(--text-secondary)\">tsz-cli</text>\n\n  <rect x=\"320\" y=\"320\" width=\"100\" height=\"30\" class=\"crate-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--text-tertiary)\"/>\n  <text x=\"370\" y=\"335\" class=\"crate-text\" fill=\"var(--text-secondary)\">tsz-lsp</text>\n\n  <rect x=\"450\" y=\"320\" width=\"120\" height=\"30\" class=\"crate-box\" fill=\"var(--bg-subtle)\" stroke=\"var(--text-tertiary)\"/>\n  <text x=\"510\" y=\"335\" class=\"crate-text\" fill=\"var(--text-secondary)\">tsz-wasm</text>\n\n  <!-- Dependency lines (top to bottom = depends on) -->\n  <line x1=\"320\" y1=\"40\" x2=\"165\" y2=\"80\" class=\"dep-line\" stroke=\"var(--text-tertiary)\" marker-end=\"url(#dep-arrow)\" opacity=\"0.4\"/>\n  <line x1=\"320\" y1=\"40\" x2=\"335\" y2=\"80\" class=\"dep-line\" stroke=\"var(--text-tertiary)\" marker-end=\"url(#dep-arrow)\" opacity=\"0.4\"/>\n  <line x1=\"165\" y1=\"110\" x2=\"300\" y2=\"80\" class=\"dep-line\" stroke=\"var(--text-tertiary)\" marker-end=\"url(#dep-arrow)\" opacity=\"0.4\"/>\n  <line x1=\"335\" y1=\"110\" x2=\"145\" y2=\"160\" class=\"dep-line\" stroke=\"var(--text-tertiary)\" marker-end=\"url(#dep-arrow)\" opacity=\"0.4\"/>\n  <line x1=\"335\" y1=\"110\" x2=\"315\" y2=\"160\" class=\"dep-line\" stroke=\"var(--text-tertiary)\" marker-end=\"url(#dep-arrow)\" opacity=\"0.4\"/>\n  <line x1=\"335\" y1=\"110\" x2=\"490\" y2=\"160\" class=\"dep-line\" stroke=\"var(--text-tertiary)\" marker-end=\"url(#dep-arrow)\" opacity=\"0.4\"/>\n  <line x1=\"145\" y1=\"190\" x2=\"300\" y2=\"240\" class=\"dep-line\" stroke=\"var(--text-tertiary)\" marker-end=\"url(#dep-arrow)\" opacity=\"0.4\"/>\n  <line x1=\"315\" y1=\"190\" x2=\"300\" y2=\"240\" class=\"dep-line\" stroke=\"var(--text-tertiary)\" marker-end=\"url(#dep-arrow)\" opacity=\"0.4\"/>\n  <line x1=\"490\" y1=\"190\" x2=\"300\" y2=\"240\" class=\"dep-line\" stroke=\"var(--text-tertiary)\" marker-end=\"url(#dep-arrow)\" opacity=\"0.4\"/>\n  <line x1=\"300\" y1=\"270\" x2=\"95\" y2=\"320\" class=\"dep-line\" stroke=\"var(--text-tertiary)\" marker-end=\"url(#dep-arrow)\" opacity=\"0.4\"/>\n  <line x1=\"300\" y1=\"270\" x2=\"240\" y2=\"320\" class=\"dep-line\" stroke=\"var(--text-tertiary)\" marker-end=\"url(#dep-arrow)\" opacity=\"0.4\"/>\n  <line x1=\"300\" y1=\"270\" x2=\"370\" y2=\"320\" class=\"dep-line\" stroke=\"var(--text-tertiary)\" marker-end=\"url(#dep-arrow)\" opacity=\"0.4\"/>\n  <line x1=\"300\" y1=\"270\" x2=\"510\" y2=\"320\" class=\"dep-line\" stroke=\"var(--text-tertiary)\" marker-end=\"url(#dep-arrow)\" opacity=\"0.4\"/>\n\n  <!-- Legend -->\n  <text x=\"320\" y=\"390\" text-anchor=\"middle\" fill=\"var(--text-tertiary)\" font-family=\"sans-serif\" font-size=\"10\">Arrows point from dependency to dependent (A &#8594; B means B depends on A)</text>\n</svg>\n</div>\n\n<h3>Crate Purposes</h3>\n\n<table>\n  <thead>\n    <tr><th>Crate</th><th>LOC</th><th>Purpose</th></tr>\n  </thead>\n  <tbody>\n    <tr><td><code>tsz-common</code></td><td>~20K</td><td>Foundation: string interner, diagnostics data, shared types</td></tr>\n    <tr><td><code>tsz-scanner</code></td><td>~4K</td><td>Lexical analysis, tokenization</td></tr>\n    <tr><td><code>tsz-parser</code></td><td>~24K</td><td>Recursive descent parser, AST node arena</td></tr>\n    <tr><td><code>tsz-binder</code></td><td>~9K</td><td>Symbols, scopes, control-flow graph</td></tr>\n    <tr><td><code>tsz-solver</code></td><td>~70K</td><td>Type relations, inference, instantiation, narrowing</td></tr>\n    <tr><td><code>tsz-lowering</code></td><td>~3K</td><td>AST-to-type bridge (converts AST type nodes to TypeIds)</td></tr>\n    <tr><td><code>tsz-checker</code></td><td>~107K</td><td>AST traversal, diagnostics orchestration</td></tr>\n    <tr><td><code>tsz-emitter</code></td><td>~54K</td><td>JavaScript and declaration file generation</td></tr>\n    <tr><td><code>tsz-lsp</code></td><td>~30K</td><td>Language Server Protocol implementation</td></tr>\n    <tr><td><code>tsz-cli</code></td><td>~26K</td><td>Command-line interface, project driver</td></tr>\n    <tr><td><code>tsz-wasm</code></td><td>~4.5K</td><td>WebAssembly bindings</td></tr>\n    <tr><td><code>conformance</code></td><td>&mdash;</td><td>Conformance test runner and infrastructure</td></tr>\n  </tbody>\n</table>\n\n<h3>Boundary Rules</h3>\n\n<p>The following cross-layer imports are <strong>forbidden</strong> and enforced by CI:</p>\n\n<ul>\n  <li>Checker must not import <code>TypeKey</code> or use raw interner APIs from Solver</li>\n  <li>Binder must not import Solver for semantic type decisions</li>\n  <li>Emitter must not import Checker internals for semantic validation</li>\n  <li>No layer may bypass the canonical query APIs to reach into another layer's private state</li>\n</ul>\n\n<hr>\n\n<!-- ════════════════════════════════════════════ -->\n<h2 id=\"principles\">7. Design Principles</h2>\n\n<h3>Solver-First</h3>\n<p>\n  If code computes type semantics&mdash;subtyping, inference, evaluation, narrowing,\n  instantiation&mdash;it belongs in the Solver. The Checker is a thin orchestration\n  layer that walks the AST and asks the Solver questions. This is the architectural\n  target; remaining checker-side semantic logic is technical debt being paid down.\n  Keeping semantics in Solver prevents logic duplication and ensures there is one source\n  of truth for \"what does this type mean?\"\n</p>\n\n<h3>Arena Everything</h3>\n<p>\n  AST nodes, symbols, flow graph nodes, and types are all arena-allocated and referenced\n  by <code>u32</code> handles. No per-operation heap allocation on hot paths. This gives\n  cache-friendly linear memory layouts, zero fragmentation, and O(1) access by index.\n  The tradeoff is that individual items can't be freed until the entire arena is dropped,\n  but compiler passes are batch operations so this is fine.\n</p>\n\n<h3>One Type Universe</h3>\n<p>\n  tsz uses one global canonical <code>TypeInterner</code> for persistent semantic types.\n  The system also supports local ephemeral <code>TypeId</code>s for scoped operations, but\n  cross-file semantic identity and relation caches are anchored to the global type universe.\n  This keeps type equality as a fast integer comparison.\n</p>\n\n<h3>tsc Parity Above All</h3>\n<p>\n  The absolute target is matching <code>tsc</code> behavior exactly. This includes diagnostics\n  (same error code, same span, same message), inference results, compatibility decisions,\n  narrowing behavior, and edge cases. When there's a conflict between \"what makes sense\" and\n  \"what tsc does,\" tsc wins. Correctness is measured by the conformance test suite, which\n  compares every diagnostic fingerprint against the official TypeScript output.\n</p>\n\n<h3>Lazy Resolution</h3>\n<p>\n  <code>TypeData::Lazy(DefId)</code> defers type resolution until someone actually needs the\n  type. This is essential for handling circular references (e.g., a linked list type that\n  refers to itself), mutual recursion between type aliases, and cross-file type dependencies.\n  The <code>TypeEnvironment</code> resolves <code>DefId &rarr; TypeId</code> on demand and\n  caches the result.\n</p>\n\n<h3>No Cross-Layer Leakage</h3>\n<p>\n  Each pipeline stage has strict boundaries that are enforced by CI. The Binder can't import\n  the Solver. The Emitter can't import the Checker. The Checker can't construct raw solver\n  types. This one-way dependency direction prevents architectural drift: new code must fit\n  into the existing responsibility model rather than taking shortcuts.\n</p>\n\n<hr>\n\n<!-- ════════════════════════════════════════════ -->\n<h2 id=\"glossary\">8. Glossary</h2>\n\n<p>\n  This glossary explains terms used throughout the codebase and this document. If you're\n  new to compilers or to this project, start here when you encounter an unfamiliar term.\n</p>\n\n<!-- ── A ── -->\n<h3 id=\"g-antecedent\">Antecedent</h3>\n<p>\n  An incoming edge in the control-flow graph. Every flow node tracks which flow nodes\n  come <em>before</em> it&mdash;those are its antecedents. A simple assignment has one\n  antecedent (the previous statement). A merge point after an <code>if/else</code> has\n  two: one from the true branch and one from the false branch. The checker walks\n  antecedent chains backward to determine what type narrowings are in effect at any\n  given point in the code.\n</p>\n\n<h3 id=\"g-arena\">Arena (Arena Allocation)</h3>\n<p>\n  A memory management strategy where objects are allocated sequentially in a large\n  contiguous block of memory, and freed all at once when the arena is dropped. Instead\n  of calling <code>malloc</code> for each AST node individually (which fragments memory\n  and is slow), the parser allocates nodes into a pre-sized <code>Vec</code> and hands\n  back an index (<code>NodeIndex</code>). This has three benefits:\n</p>\n<ul>\n  <li><strong>Speed:</strong> Allocation is just bumping an index. No allocator overhead.</li>\n  <li><strong>Cache friendliness:</strong> Nodes are contiguous in memory, so the CPU prefetcher loads them efficiently.</li>\n  <li><strong>No fragmentation:</strong> One big block instead of thousands of small ones scattered across the heap.</li>\n</ul>\n<p>\n  The tradeoff is that you can't free individual items&mdash;only the whole arena at once.\n  This is fine for compilers, which are batch operations: parse a file, check it, emit it,\n  then throw away all the data.\n</p>\n\n<h3 id=\"g-ast\">AST (Abstract Syntax Tree)</h3>\n<p>\n  A tree representation of the syntactic structure of source code. The parser reads\n  <code>let x: string = 42</code> and produces a tree where a <code>VariableStatement</code>\n  node contains a <code>VariableDeclarationList</code>, which contains a\n  <code>VariableDeclaration</code> with children for the name, type annotation, and\n  initializer. \"Abstract\" means it doesn't include every character (like semicolons or\n  parentheses used only for grouping)&mdash;it captures the <em>structure</em>, not the\n  exact characters. In tsz, the AST is stored in a <code>NodeArena</code> as compact\n  16-byte node headers.\n</p>\n\n<h3 id=\"g-atom\">Atom</h3>\n<p>\n  A <code>u32</code> handle representing an interned string. When the scanner sees the\n  identifier <code>x</code>, it doesn't store the string \"x\" directly&mdash;it stores it\n  once in a global string table and returns <code>Atom(47)</code> (or whatever index it\n  gets). Every subsequent occurrence of <code>x</code> anywhere in the program gets the\n  same <code>Atom(47)</code>. This means comparing two identifiers for equality is just\n  comparing two integers, which is O(1) regardless of string length. Defined in\n  <code>tsz-common/src/interner.rs</code>.\n</p>\n\n<!-- ── B ── -->\n<h3 id=\"g-bivariant\">Bivariance</h3>\n<p>\n  A variance mode where type parameters are checked in <em>both</em> directions. If\n  <code>Dog extends Animal</code>, then under bivariance, <code>(x: Dog) =&gt; void</code>\n  is assignable to <code>(x: Animal) =&gt; void</code> <em>and</em> vice versa. This is\n  unsound (it allows calling a function with the wrong argument type) but TypeScript uses\n  it by default for method parameters for backwards compatibility. See also\n  <a href=\"#g-variance\">Variance</a>.\n</p>\n\n<h3 id=\"g-bottom-type\">Bottom Type</h3>\n<p>\n  A type that is a subtype of every other type. In TypeScript, this is <code>never</code>\n  (<code>TypeId(2)</code>). A value of type <code>never</code> can be assigned to any type,\n  but no value can actually <em>be</em> of type <code>never</code>. It represents impossible\n  states, like the return type of a function that always throws. Opposite of\n  <a href=\"#g-top-type\">Top Type</a>.\n</p>\n\n<!-- ── C ── -->\n<h3 id=\"g-cache-line\">Cache Line</h3>\n<p>\n  The smallest unit of data the CPU transfers between main memory and the CPU cache.\n  On most modern processors, a cache line is 64 bytes. When the CPU reads one byte, it\n  actually loads the entire 64-byte block containing that byte. This is why tsz's 16-byte\n  AST node headers matter: four nodes fit in one cache line, so iterating over nodes is\n  very fast because the CPU loads four at a time.\n</p>\n\n<h3 id=\"g-coinductive\">Coinductive Semantics (Greatest Fixed Point)</h3>\n<p>\n  A strategy for handling recursive types during subtype checking. The problem: when\n  checking whether <code>interface List { next: List }</code> is a subtype of itself, a\n  naive algorithm would loop forever (to check <code>List &lt;: List</code>, it needs to\n  check <code>List &lt;: List</code>, and so on). Coinductive semantics solves this by\n  keeping a <em>cycle stack</em> of type pairs currently being checked. When the solver\n  encounters a pair that's already on the stack, it returns \"yes\" (assumes the check\n  succeeds). This is mathematically called the Greatest Fixed Point (GFP): assume\n  everything works until proven otherwise. The alternative (Least Fixed Point, or\n  inductive) would assume failure, which gives wrong results for recursive types.\n</p>\n\n<h3 id=\"g-conformance\">Conformance</h3>\n<p>\n  The measure of how closely tsz matches <code>tsc</code>'s output. A conformance test\n  passes when tsz produces exactly the same set of diagnostics as <code>tsc</code> for a\n  given input file&mdash;same error code (e.g., TS2322), same file, same line, same column,\n  same message text. The official TypeScript conformance test suite has ~12,500 tests.\n  As of 2026-02-22, tsz passes 60.8% (7,650/12,574). See the README for the latest figure.\n</p>\n\n<h3 id=\"g-contravariant\">Contravariance</h3>\n<p>\n  A variance mode where the subtype relationship is <em>reversed</em>. Function parameters\n  are contravariant: if <code>Dog extends Animal</code>, then <code>(x: Animal) =&gt; void</code>\n  is assignable to <code>(x: Dog) =&gt; void</code> (the <em>broader</em> parameter type is\n  the subtype). This is sound because a function that accepts any Animal can safely be called\n  where a function accepting only Dogs is expected&mdash;it can handle Dogs and more.\n  See also <a href=\"#g-variance\">Variance</a>.\n</p>\n\n<h3 id=\"g-covariant\">Covariance</h3>\n<p>\n  A variance mode where the subtype relationship goes in the <em>same</em> direction.\n  Return types and property types are covariant: if <code>Dog extends Animal</code>, then\n  <code>() =&gt; Dog</code> is assignable to <code>() =&gt; Animal</code>. This is sound\n  because anywhere you expect an Animal, receiving a Dog is fine.\n  See also <a href=\"#g-variance\">Variance</a>.\n</p>\n\n<!-- ── D ── -->\n<h3 id=\"g-defid\">DefId</h3>\n<p>\n  A stable identifier for a type <em>definition</em> (not a type value). When the checker\n  encounters a type reference like <code>User</code> that hasn't been fully resolved yet,\n  it creates a <code>DefId</code> and the solver stores it as <code>Lazy(DefId)</code>. Later,\n  when someone actually needs the type (e.g., during a subtype check), the\n  <code>TypeEnvironment</code> resolves the <code>DefId</code> to a concrete <code>TypeId</code>.\n  This lazy approach prevents infinite loops when types reference each other circularly.\n</p>\n\n<h3 id=\"g-diagnostic\">Diagnostic</h3>\n<p>\n  A compiler message reported to the user. In TypeScript, each diagnostic has an error\n  code (e.g., TS2322), a severity (error, warning, suggestion), a source location (file,\n  line, column), and a message. Example: <code>error TS2322: Type 'number' is not assignable\n  to type 'string'</code>. tsz must produce diagnostics identical to <code>tsc</code> for\n  conformance tests to pass.\n</p>\n\n<h3 id=\"g-discriminated-union\">Discriminated Union</h3>\n<p>\n  A union type where each member has a shared property with a unique literal type that\n  identifies it. Example: <code>{ kind: \"circle\", radius: number } | { kind: \"square\",\n  side: number }</code>. The <code>kind</code> property is the \"discriminant.\" When you\n  check <code>if (shape.kind === \"circle\")</code>, the solver can narrow the type to just\n  the circle variant. This is a common pattern in TypeScript.\n</p>\n\n<!-- ── E ── -->\n<h3 id=\"g-excess-property\">Excess Property Checking</h3>\n<p>\n  A TypeScript-specific check that reports an error when an object literal has properties\n  not declared in the target type. Normally, structural typing allows extra properties\n  (width subtyping), but when you write a literal directly:\n</p>\n<pre><code><span class=\"kw\">const</span> x: { a: <span class=\"ty\">number</span> } = { a: <span class=\"num\">1</span>, b: <span class=\"num\">2</span> };  <span class=\"cm\">// Error: 'b' does not exist on type</span></code></pre>\n<p>\n  TypeScript reports the extra <code>b</code>. This only happens when the object is \"fresh\"\n  (a literal at the assignment site). If you assign through a variable, the freshness is lost\n  and extra properties are silently allowed. See also <a href=\"#g-freshness\">Freshness</a>.\n</p>\n\n<!-- ── F ── -->\n<h3 id=\"g-flow-graph\">Flow Graph (Control-Flow Graph / CFG)</h3>\n<p>\n  A graph built by the binder that models how execution flows through the program. Nodes\n  represent program points (assignments, conditions, function entries). Edges represent\n  possible execution paths. The checker uses this graph for <a href=\"#g-narrowing\">type\n  narrowing</a>: after <code>if (x !== null)</code>, the true branch knows <code>x</code>\n  is not null by tracing backward through the flow graph. Each flow node is identified by\n  a <code>FlowNodeId(u32)</code> and tracks its <a href=\"#g-antecedent\">antecedents</a>.\n</p>\n\n<h3 id=\"g-freshness\">Freshness</h3>\n<p>\n  A flag on object types that indicates the type was created from an object literal\n  <em>at the current assignment site</em>. Fresh objects trigger\n  <a href=\"#g-excess-property\">excess property checking</a>. Once the object is assigned\n  to a variable or passed through a function, the freshness flag is removed and excess\n  property checking no longer applies. This is managed by the Lawyer (CompatChecker) layer\n  in the solver.\n</p>\n\n<!-- ── H ── -->\n<h3 id=\"g-hash-consing\">Hash-Consing</h3>\n<p>\n  A technique for deduplicating data structures by storing each unique value exactly once.\n  When you want to create a new value, you first hash it and check if an identical value\n  already exists. If so, return the existing handle; if not, store the new value and return\n  a fresh handle. In tsz, the <code>TypeInterner</code> hash-conses types: creating the type\n  <code>string | number</code> twice returns the same <code>TypeId</code> both times. The\n  string interner does the same for identifiers (returning the same <code>Atom</code>).\n  This is the core mechanism behind O(1) equality checks.\n</p>\n\n<h3 id=\"g-hoisting\">Hoisting</h3>\n<p>\n  A JavaScript/TypeScript behavior where certain declarations are treated as if they appear\n  at the top of their scope, even if they're written later in the code. <code>var</code>\n  declarations and <code>function</code> declarations are hoisted&mdash;you can reference\n  them before their textual position. <code>let</code> and <code>const</code> are <em>not</em>\n  hoisted (they exist in a \"temporal dead zone\" until their declaration). The binder handles\n  this with a multi-pass strategy: first pass collects hoisted declarations, second pass\n  processes block-scoped declarations.\n</p>\n\n<!-- ── I ── -->\n<h3 id=\"g-instantiation\">Instantiation</h3>\n<p>\n  The process of replacing generic type parameters with concrete types. When you write\n  <code>Array&lt;string&gt;</code>, the solver takes the generic <code>Array&lt;T&gt;</code>\n  definition and substitutes <code>T</code> with <code>string</code> throughout the entire\n  type structure. This happens recursively: if the array's methods reference <code>T</code>,\n  those get substituted too. The solver caches instantiation results so that\n  <code>Array&lt;string&gt;</code> used in two different places produces the same\n  <code>TypeId</code>. Implemented in <code>tsz-solver/src/instantiation/</code>.\n</p>\n\n<h3 id=\"g-interner\">Interner (String Interner / Type Interner)</h3>\n<p>\n  A data structure that stores unique values and returns lightweight handles to them. Think\n  of it as a two-way lookup table:\n</p>\n<ul>\n  <li><strong>Forward:</strong> Given a string like <code>\"getElementById\"</code>, return its <code>Atom(u32)</code>.</li>\n  <li><strong>Reverse:</strong> Given an <code>Atom(u32)</code>, return the original string.</li>\n</ul>\n<p>\n  The first time you intern a string, it's stored and you get back an integer handle. Every\n  subsequent time you intern the same string, you get back the <em>same</em> integer without\n  storing it again. tsz has two interners:\n</p>\n<ul>\n  <li><strong>String interner</strong> (<code>tsz-common</code>): Maps strings to <code>Atom(u32)</code>. Used for all identifiers, keywords, and string content.</li>\n  <li><strong>Type interner</strong> (<code>tsz-solver</code>): Maps type structures (<code>TypeData</code>) to <code>TypeId(u32)</code>. Used for all types.</li>\n</ul>\n<p>\n  The key benefit: once interned, <em>equality is just integer comparison</em>. Checking\n  whether two 100-character identifiers are the same string is a single <code>==</code>\n  on two <code>u32</code> values.\n</p>\n\n<h3 id=\"g-ir\">IR (Intermediate Representation)</h3>\n<p>\n  A structured tree used by the emitter as a middle step between the TypeScript AST and\n  the final JavaScript text output. When the emitter needs to transform TypeScript-specific\n  syntax into JavaScript (e.g., converting an ES2015+ class to ES5 prototype chains, or\n  converting <code>async/await</code> to state machines), it doesn't manipulate strings\n  directly. Instead:\n</p>\n<ol>\n  <li><strong>Transform phase:</strong> A transform function reads the AST and produces an IR tree made of <code>IRNode</code> variants (<code>FunctionExpr</code>, <code>CallExpr</code>, <code>VarDecl</code>, <code>BinaryExpr</code>, <code>Block</code>, etc.).</li>\n  <li><strong>Print phase:</strong> The <code>IRPrinter</code> walks the IR tree and emits JavaScript text with correct formatting, indentation, and semicolons.</li>\n</ol>\n<p>\n  This two-phase approach keeps transforms clean (they describe <em>what</em> the output\n  should look like structurally) and keeps formatting concerns separate (the printer handles\n  <em>how</em> to render it). The IR lives in <code>tsz-emitter/src/transforms/ir.rs</code>.\n</p>\n\n<!-- ── L ── -->\n<h3 id=\"g-lowering\">Lowering</h3>\n<p>\n  The process of converting AST type syntax nodes into solver <code>TypeId</code>s. When\n  the checker sees a <code>TypeReference</code> node for <code>string</code> in the AST,\n  the lowering layer (<code>tsz-lowering</code>) converts that AST node into\n  <code>TypeId::STRING</code>. For more complex types like <code>{ name: string, age: number }</code>,\n  lowering recursively converts each part and interns the resulting <code>Object</code> type.\n  This is a bridge between the parser's syntax world and the solver's type world.\n</p>\n\n<!-- ── M ── -->\n<h3 id=\"g-memoization\">Memoization</h3>\n<p>\n  Caching the results of expensive computations so they don't need to be repeated. The\n  solver maintains several caches:\n</p>\n<ul>\n  <li><strong>Relation cache:</strong> \"Is <code>A</code> assignable to <code>B</code>?\" Once checked, the result is cached. The next time the same pair is queried, it's an O(1) lookup.</li>\n  <li><strong>Evaluation cache:</strong> \"What does <code>T extends string ? 'yes' : 'no'</code> evaluate to?\" Cached after first evaluation.</li>\n  <li><strong>Property cache:</strong> \"What type is the <code>name</code> property of type <code>T</code>?\" Cached per (type, property-name) pair.</li>\n  <li><strong>Instantiation cache:</strong> \"What is <code>Array&lt;string&gt;</code>?\" Cached per (generic, arguments) tuple.</li>\n</ul>\n<p>\n  Without memoization, checking a complex program would repeat the same type computations\n  millions of times. With it, each unique computation happens once.\n</p>\n\n<!-- ── N ── -->\n<h3 id=\"g-narrowing\">Narrowing (Type Narrowing)</h3>\n<p>\n  The process of refining a type based on runtime checks. When you write:\n</p>\n<pre><code><span class=\"kw\">function</span> <span class=\"fn\">f</span>(x: <span class=\"ty\">string</span> | <span class=\"ty\">number</span>) {\n  <span class=\"kw\">if</span> (<span class=\"kw\">typeof</span> x === <span class=\"str\">\"string\"</span>) {\n    <span class=\"cm\">// Here, x is narrowed from string | number to just string</span>\n    x.toUpperCase();  <span class=\"cm\">// OK: string has toUpperCase</span>\n  } <span class=\"kw\">else</span> {\n    <span class=\"cm\">// Here, x is narrowed to just number</span>\n    x.toFixed();      <span class=\"cm\">// OK: number has toFixed</span>\n  }\n}</code></pre>\n<p>\n  The checker extracts \"type guards\" from the AST (like <code>typeof x === \"string\"</code>)\n  and passes them to the solver, which computes the narrowed type for each branch. The\n  solver handles union filtering, <code>instanceof</code>, discriminated unions, truthiness\n  checks, <code>in</code> operator, and user-defined type predicates. The flow graph built\n  by the binder tells the checker which guards are active at each point in the code.\n</p>\n\n<h3 id=\"g-node-arena\">NodeArena</h3>\n<p>\n  The arena that stores all AST nodes. Each node has a 16-byte header (<code>kind</code>,\n  <code>flags</code>, <code>pos</code>, <code>end</code>, <code>data_index</code>) stored\n  contiguously. Variable-sized payloads (child lists, string data) are stored in typed\n  side pools, one per AST node kind. For example, all <code>IdentifierData</code> payloads\n  are stored together in one pool, all <code>CallExpressionData</code> in another. The\n  <code>data_index</code> field in the header points into the right pool. This keeps the\n  main node array compact (4 nodes per cache line).\n</p>\n\n<h3 id=\"g-node-index\">NodeIndex</h3>\n<p>\n  A handle (index) into the <code>NodeArena</code>. Instead of using a pointer to reference\n  an AST node, the parser returns a <code>NodeIndex</code> which is just an offset into the\n  arena's array. Looking up a node by its index is O(1) (simple array indexing). Using\n  indices instead of pointers also makes serialization trivial and avoids dangling pointer\n  bugs.\n</p>\n\n<!-- ── Q ── -->\n<h3 id=\"g-query-boundaries\">Query Boundaries</h3>\n<p>\n  The gateway API in the checker (<code>tsz-checker/src/query_boundaries/</code>) that\n  routes type-checking questions to the solver. Instead of the checker calling solver\n  methods directly all over the codebase, assignability checks for TS2322/TS2345/TS2416\n  diagnostics must go through these boundary functions. This centralization ensures\n  consistent behavior: the boundary handles relation checking, failure reason extraction,\n  suppression policy, and diagnostic rendering in one place.\n</p>\n\n<!-- ── R ── -->\n<h3 id=\"g-recursive-descent\">Recursive Descent Parser</h3>\n<p>\n  A parsing strategy where each grammar rule becomes a function, and parsing works by\n  calling these functions recursively. For example, parsing an expression calls\n  <code>parse_binary_expression()</code>, which calls <code>parse_unary_expression()</code>,\n  which calls <code>parse_primary_expression()</code>. It's called \"recursive\" because\n  these functions call each other, and \"descent\" because it starts from the top-level rule\n  (source file) and works its way down into nested sub-expressions. This is the same\n  approach used by <code>tsc</code> itself.\n</p>\n\n<!-- ── S ── -->\n<h3 id=\"g-scope-tree\">Scope Tree</h3>\n<p>\n  A tree of lexical scopes built by the binder. Each scope knows its parent scope and\n  contains a symbol table mapping names to <code>SymbolId</code>s. When the checker needs\n  to resolve a name like <code>x</code>, it looks in the current scope first, then walks\n  up the parent chain until it finds it. Unlike a stack-based approach (push scope on\n  entry, pop on exit), tsz uses a persistent tree: scopes are never destroyed. This is\n  important for incremental compilation&mdash;you can query a scope later without\n  re-building it.\n</p>\n\n<h3 id=\"g-side-pool\">Side Pool (Typed Side Pool)</h3>\n<p>\n  A secondary array in the <code>NodeArena</code> that stores variable-sized data for a\n  specific AST node kind. The 16-byte node header is too small to hold things like a\n  function's parameter list or a class's member list. So the header has a\n  <code>data_index</code> field that points into a typed side pool. There are 40+ pools:\n  <code>IdentifierData</code>, <code>BinaryExpressionData</code>,\n  <code>FunctionDeclarationData</code>, etc. Each pool only stores data for its specific\n  node kind, keeping things tightly packed and cache-friendly.\n</p>\n\n<h3 id=\"g-structural-typing\">Structural Typing</h3>\n<p>\n  TypeScript's approach to type compatibility: types are compatible based on their\n  <em>structure</em> (what properties and methods they have), not their <em>name</em>\n  or declaration site. If interface <code>A</code> has <code>{ name: string }</code> and\n  interface <code>B</code> also has <code>{ name: string }</code>, they are compatible\n  even though they're different declarations. This is different from \"nominal typing\"\n  (used by Java, C#) where two classes with identical structures are different types if\n  they have different names.\n</p>\n\n<h3 id=\"g-symbol\">Symbol / SymbolId</h3>\n<p>\n  A named entity in the program: a variable, function, class, interface, enum member, etc.\n  The binder creates a <code>Symbol</code> record for each declaration and assigns it a\n  <code>SymbolId(u32)</code> handle in the symbol arena. The symbol stores the entity's\n  name, kind flags, declaration nodes, parent symbol, and optional member/export tables.\n  The checker uses <code>SymbolId</code> to look up what type corresponds to a given name.\n</p>\n\n<h3 id=\"g-syntax-kind\">SyntaxKind</h3>\n<p>\n  A <code>u16</code> enum that identifies what kind of token or AST node something is.\n  There are ~400 variants covering all of TypeScript: <code>LetKeyword = 121</code>,\n  <code>Identifier = 80</code>, <code>VariableDeclaration = 261</code>,\n  <code>IfStatement = 246</code>, etc. Every node header and every token carries a\n  SyntaxKind. This is how the compiler knows what it's looking at without needing\n  inheritance hierarchies or trait objects.\n</p>\n\n<!-- ── T ── -->\n<h3 id=\"g-top-type\">Top Type</h3>\n<p>\n  A type that is a supertype of every other type. In TypeScript, <code>unknown</code>\n  (<code>TypeId(3)</code>) is the true top type: any value is assignable to\n  <code>unknown</code>. The type <code>any</code> (<code>TypeId(4)</code>) is special: it\n  acts as both a top type <em>and</em> a bottom type (assignable to and from everything),\n  which is intentionally unsound but serves as TypeScript's escape hatch.\n  Opposite of <a href=\"#g-bottom-type\">Bottom Type</a>.\n</p>\n\n<h3 id=\"g-type-environment\">TypeEnvironment</h3>\n<p>\n  The runtime context that resolves <code>DefId &rarr; TypeId</code> during type evaluation\n  and relation checks. When the solver encounters a <code>Lazy(DefId)</code> type, it asks\n  the TypeEnvironment to look up (or compute and cache) the concrete <code>TypeId</code>.\n  The environment also carries type parameter bindings during generic instantiation, so\n  that <code>T</code> resolves to the right concrete type within a given context.\n</p>\n\n<h3 id=\"g-typeid\">TypeId</h3>\n<p>\n  A <code>u32</code> handle into the global type interner. The most important type in the\n  compiler. Every type in the program&mdash;from <code>string</code> to\n  <code>Map&lt;string, Promise&lt;number[]&gt;&gt;</code>&mdash;is represented by a\n  single <code>TypeId</code>. Comparing two types is comparing two integers:\n  <code>type_a == type_b</code>. The first 100 IDs (0&ndash;99) are reserved for built-in\n  types like <code>string</code>, <code>number</code>, <code>any</code>, <code>never</code>,\n  etc. User-defined types start at ID 100.\n</p>\n\n<h3 id=\"g-typedata\">TypeData / TypeKey</h3>\n<p>\n  The actual structural representation of a type. <code>TypeData</code> is the public name\n  used at API boundaries; <code>TypeKey</code> is the crate-private internal enum in the\n  solver. It has variants for every kind of TypeScript type: <code>Intrinsic</code> (primitives),\n  <code>Object</code> (structural objects), <code>Union</code>, <code>Intersection</code>,\n  <code>Function</code>, <code>Conditional</code>, <code>Mapped</code>, etc. Checker code\n  must not match on <code>TypeKey</code> directly&mdash;it should use solver query APIs instead.\n</p>\n\n<h3 id=\"g-type-guard\">Type Guard</h3>\n<p>\n  A runtime expression that the compiler uses to narrow a type. Examples:\n  <code>typeof x === \"string\"</code>, <code>x instanceof Array</code>,\n  <code>\"prop\" in x</code>, or a user-defined predicate function like\n  <code>function isString(x: unknown): x is string</code>. The checker extracts type guards\n  from the AST and converts them to solver <code>TypeGuard</code> structs, then the solver\n  computes the narrowed type.\n</p>\n\n<!-- ── V ── -->\n<h3 id=\"g-variance\">Variance</h3>\n<p>\n  How a type parameter's subtype relationship affects the subtype relationship of the\n  containing type. There are four variance modes:\n</p>\n<ul>\n  <li><strong><a href=\"#g-covariant\">Covariant</a>:</strong> Same direction. <code>Dog extends Animal</code> implies <code>Array&lt;Dog&gt; extends Array&lt;Animal&gt;</code>.</li>\n  <li><strong><a href=\"#g-contravariant\">Contravariant</a>:</strong> Opposite direction. Function parameters go this way for soundness.</li>\n  <li><strong><a href=\"#g-bivariant\">Bivariant</a>:</strong> Both directions. TypeScript's (unsound) default for method parameters.</li>\n  <li><strong>Invariant:</strong> Neither direction. Mutable references need this for soundness.</li>\n</ul>\n<p>\n  In tsz, the Judge (SubtypeChecker) uses strict variance rules, and the Lawyer\n  (CompatChecker) overrides them where TypeScript's legacy behavior requires it (e.g.,\n  bivariant method parameters).\n</p>\n\n<h3 id=\"g-visitor\">Visitor (TypeVisitor)</h3>\n<p>\n  A design pattern for traversing the type graph systematically. Instead of writing a\n  <code>match</code> on all 20+ <code>TypeKey</code> variants at every call site, the\n  solver provides a <code>TypeVisitor</code> trait. You implement a few methods (e.g.,\n  \"what to do when visiting a Union\"), and the visitor handles walking the complete\n  type structure, including recursion into nested types, cycle detection, and so on. This\n  prevents bugs where a new type variant is added but some call sites forget to handle it.\n</p>\n\n<!-- ── W ── -->\n<h3 id=\"g-width-subtyping\">Width Subtyping</h3>\n<p>\n  The rule that a type with <em>more</em> properties is a subtype of a type with\n  <em>fewer</em> properties. <code>{ a: number, b: string }</code> is assignable to\n  <code>{ a: number }</code> because it has everything <code>{ a: number }</code> requires\n  (the <code>a</code> property) plus an extra <code>b</code>. This is the default behavior\n  of structural typing. <a href=\"#g-excess-property\">Excess property checking</a>\n  (triggered by <a href=\"#g-freshness\">freshness</a>) is the exception: it rejects the\n  extra properties for object literals to catch typos.\n</p>\n\n\n\n</main>\n</div>\n\n<!-- ── Sidebar scroll tracking ── -->",
  "scripts": "<script>\nconst links = document.querySelectorAll('.sidebar a[href^=\"#\"]');\nconst sections = [];\nlinks.forEach(link => {\n  const id = link.getAttribute('href').slice(1);\n  const el = document.getElementById(id);\n  if (el) sections.push({ el, link });\n});\n\nfunction updateActive() {\n  let current = sections[0];\n  for (const s of sections) {\n    if (s.el.getBoundingClientRect().top <= 100) current = s;\n  }\n  links.forEach(l => l.classList.remove('active'));\n  if (current) current.link.classList.add('active');\n}\n\nwindow.addEventListener('scroll', updateActive, { passive: true });\nupdateActive();\n\n// Close sidebar on mobile when clicking a link\nlinks.forEach(link => {\n  link.addEventListener('click', () => {\n    document.querySelector('.sidebar').classList.remove('open');\n  });\n});\n</script>"
};
